// Parse the 9 strategies from Ollama output
const agentOutput = $input.first().json.output || $input.first().json.text || '';

let strategies = [];
try {
  // Try to parse JSON from the agent output
  const jsonMatch = agentOutput.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (jsonMatch) {
    strategies = JSON.parse(jsonMatch[0]);
  } else {
    strategies = JSON.parse(agentOutput);
  }
} catch (e) {
  return [{ json: { error: 'Failed to parse strategies JSON from Ollama output', raw: agentOutput, parseError: e.message } }];
}

if (!Array.isArray(strategies) || strategies.length === 0) {
  return [{ json: { error: 'No strategies found in output', raw: agentOutput } }];
}

// Enrich each strategy with metadata
const enriched = strategies.map(s => ({
  json: {
    ...s,
    timeframe: '15min',
    start_date: '2024-01-01',
    end_date: '2024-12-31',
    source: 'ollama'
  }
}));

return enriched;

// Filter results to only TIER_1 and TIER_2 strategies
const items = $input.all();
const validTiers = ['TIER_1', 'TIER_2'];

// Handle both array-in-single-item and multi-item formats
let allResults = [];
for (const item of items) {
  if (Array.isArray(item.json)) {
    allResults.push(...item.json);
  } else if (item.json.data && Array.isArray(item.json.data)) {
    allResults.push(...item.json.data);
  } else {
    allResults.push(item.json);
  }
}

const passed = allResults.filter(r => validTiers.includes(r.tier));

return [{ json: { strategies: passed, count: passed.length, hasPassed: passed.length > 0 } }];

const items = $input.all();
let scoutedIdeas = [];

for (const item of items) {
  const d = item.json;
  if (Array.isArray(d)) scoutedIdeas = d;
  else if (d.ideas && Array.isArray(d.ideas)) scoutedIdeas = d.ideas;
  else if (d.entries && Array.isArray(d.entries)) scoutedIdeas = d.entries;
  else if (d.data && Array.isArray(d.data)) scoutedIdeas = d.data;
}

let scoutContext = '';
if (scoutedIdeas.length > 0) {
  const ideaSummaries = scoutedIdeas.slice(0, 10).map((idea, i) => {
    const title = idea.title || idea.name || 'Untitled';
    const summary = idea.summary || idea.description || '';
    const source = idea.source || 'unknown';
    return `${i + 1}. [${source}] ${title}: ${summary.substring(0, 150)}`;
  }).join('\n');
  scoutContext = `\n\nRecent research discoveries to consider when generating strategies:\n${ideaSummaries}`;
}

return [{ json: { scoutContext, scoutedIdeaCount: scoutedIdeas.length } }];

